"use strict";
const Commons = require("../utils/commons");
const RequestUtils = require("../utils/requestUtils");
async function getBalance(apiKey) {
    const statusResponse = await RequestUtils.sendRequestTo(Commons.serverBaseUrl() + '/balance/?apikey=' + apiKey, {}, null, 'get', true);
    if (statusResponse.response.error && statusResponse.response.error.msg) {
        return {
            success: false,
            message: statusResponse.response.error.msg,
            balances: [],
        };
    }
    if (statusResponse.response.error) {
        return {
            success: false,
            message: 'error',
            balances: [],
        };
    }
    if (!/^2../.test(statusResponse.status.code)) {
        return Object.assign({ success: false, message: 'error', balances: [] }, statusResponse.response);
    }
    return Object.assign({ success: true, message: '', balances: [] }, statusResponse.response);
}
module.exports = getBalance;
